15	const THREE_YEARS_MS = 3 * 365 * 24 * 60 * 60 * 1000;
16	
17	@Injectable()
18	export class JiraSyncService {
19		private readonly logger = new Logger(JiraSyncService.name);
20	
21		constructor(
22			private readonly installationModel: JiraInstallationModel,
23			private readonly projectModel: JiraProjectModel,
24			private readonly issueModel: JiraIssueModel,
25			private readonly changelogModel: JiraChangelogModel,
26			private readonly worklogModel: JiraWorklogModel,
27			private readonly sprintModel: JiraSprintModel,
28			private readonly jiraApiService: JiraApiService,
29			@InjectQueue('jira') private readonly jiraQueue: Queue,
30		) {}
31	
32		async discoverProjects({ installationDbId }: { installationDbId: string }): Promise<void> {
33			const installation = await this.installationModel.findById({ id: installationDbId });
34	
35			if (!installation) {
36				this.logger.warn(`Installation ${installationDbId} not found`);
37				return;
38			}
39	
40			const token = await this.jiraApiService.getValidToken({ installation });
41			const projects = await this.jiraApiService.listProjects({
42				cloudId: installation.cloud_id,
43				token,
44			});
45	
46			await this.projectModel.upsertMany({ installationId: installationDbId, projects });
47	
48			const savedProjects = await this.projectModel.findByInstallationId({
49				installationId: installationDbId,
50			});
51	
52			for (const project of savedProjects) {
53				await this.jiraQueue.add(
54					'sync_project',
55					{
56						installationDbId,
57						projectDbId: project._id,
58						projectKey: project.project_key,
59						projectId: project.project_id,
60					},
61					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
62				);
63			}
64	
65			this.logger.debug(
66				`Enqueued sync for ${savedProjects.length} projects in installation ${installationDbId}`,
67			);
68		}
69	
70		async syncProject({
71			installationDbId,
72			projectDbId,
73			projectKey,
74		}: {
75			installationDbId: string;
76			projectDbId: string;
77			projectKey: string;
78		}): Promise<void> {
79			const installation = await this.installationModel.findById({ id: installationDbId });
80	
81			if (!installation) {
82				this.logger.warn(`Installation ${installationDbId} not found`);
83				return;
84			}
85	
86			const projects = await this.projectModel.findByInstallationId({
87				installationId: installationDbId,
88			});
89			const project = projects.find((p) => p._id === projectDbId);
90	
91			if (!project) {
92				this.logger.warn(`Project ${projectDbId} not found`);
93				return;
94			}
95	
96			const token = await this.jiraApiService.getValidToken({ installation });
97	
98			const since = project.last_synced_at
99				? project.last_synced_at
100				: new Date(Date.now() - THREE_YEARS_MS);
101	
102			const sinceStr = since.toISOString().split('T')[0] ?? since.toISOString();
103			const jql = `project = "${projectKey}" AND updated >= "${sinceStr}" ORDER BY updated ASC`;
104	
105			await this.fetchAndStoreIssues({
106				installationDbId,
107				projectDbId,
108				cloudId: installation.cloud_id,
109				token,
110				jql,
111			});
112	
113			await this.fetchAndStoreSprints({
114				installationDbId,
115				projectKey,
116				cloudId: installation.cloud_id,
117				token,
118			});
119	
120			await this.projectModel.updateLastSyncedAt({ id: projectDbId });
121	
122			this.logger.debug(`Sync complete for project ${projectKey} in installation ${installationDbId}`);
123		}
124	
125		async pollAllInstallations(): Promise<void> {
126			const installations = await this.installationModel.findAllActive();
127	
128			for (const installation of installations) {
129				await this.jiraQueue.add(
130					'discover_projects',
131					{ installationDbId: installation._id },
132					{ attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
133				);
134			}
135	
136			this.logger.debug(`Triggered discover_projects for ${installations.length} active installations`);
137		}
