139		private async fetchAndStoreIssues({
140			installationDbId,
141			projectDbId,
142			cloudId,
143			token,
144			jql,
145		}: {
146			installationDbId: string;
147			projectDbId: string;
148			cloudId: string;
149			token: string;
150			jql: string;
151		}): Promise<void> {
152			let startAt = 0;
153			const pageSize = 100;
154	
155			while (true) {
156				const response = await this.jiraApiService.searchIssues({
157					cloudId,
158					token,
159					jql,
160					startAt,
161				});
162	
163				if (response.issues.length === 0) break;
164	
165				const savedIssues = await this.issueModel.upsertMany({
166					issues: response.issues.map((issue) => ({
167						installation_id: installationDbId,
168						project_id: projectDbId,
169						issue_key: issue.key,
170						issue_id: issue.id,
171						issue_type: issue.fields.issuetype?.name ?? null,
172						status: issue.fields.status?.name ?? null,
173						priority: issue.fields.priority?.name ?? null,
174						assignee_id: issue.fields.assignee?.accountId ?? null,
175						reporter_id: issue.fields.reporter?.accountId ?? null,
176						story_points: issue.fields.customfield_10016 ?? null,
177						updated_at: new Date(issue.fields.updated),
178						resolved_at: issue.fields.resolutiondate
179							? new Date(issue.fields.resolutiondate)
180							: null,
181					})),
182				});
183	
184				await this.storeChangelogs({
185					installationDbId,
186					issues: response.issues,
187					savedIssues,
188				});
189	
190				await this.storeWorklogs({
191					installationDbId,
192					cloudId,
193					token,
194					issues: response.issues,
195					savedIssues,
196				});
197	
198				startAt += pageSize;
199				if (startAt >= response.total || response.issues.length < pageSize) break;
200			}
201		}
